// Get all items from merged sheets
const items = $input.all();
const sales = items.map(i => i.json);

// Filter only Fact_Sales rows (they have OrderID)
const factSales = sales.filter(r => r.OrderID);

// ── BASIC METRICS ──────────────────────────────────────────
const totalRevenue = factSales.reduce((s, r) => s + (parseFloat(r.Revenue) || 0), 0);
const totalProfit  = factSales.reduce((s, r) => s + (parseFloat(r.Profit) || 0), 0);
const totalOrders  = factSales.length;
const totalQty     = factSales.reduce((s, r) => s + (parseInt(r.Quantity) || 0), 0);
const profitMargin = totalRevenue ? ((totalProfit / totalRevenue) * 100).toFixed(2) : 0;
const avgOrderVal  = totalOrders  ? (totalRevenue / totalOrders).toFixed(2) : 0;

// ── REVENUE BY PRODUCT ─────────────────────────────────────
const byProduct = {};
factSales.forEach(r => {
  const key = r.Product || 'Unknown';
  byProduct[key] = (byProduct[key] || 0) + (parseFloat(r.Revenue) || 0);
});
const byProductSorted = Object.entries(byProduct).sort((a, b) => b[1] - a[1]);
const topProduct    = byProductSorted[0]?.[0] || 'N/A';
const topProductRev = byProductSorted[0]?.[1] || 0;

// ── REVENUE BY CUSTOMER ────────────────────────────────────
const byCustomer = {};
factSales.forEach(r => {
  const key = r.Customer || 'Unknown';
  byCustomer[key] = (byCustomer[key] || 0) + (parseFloat(r.Revenue) || 0);
});
const byCustomerSorted = Object.entries(byCustomer).sort((a, b) => b[1] - a[1]);
const topCustomer    = byCustomerSorted[0]?.[0] || 'N/A';
const topCustomerRev = byCustomerSorted[0]?.[1] || 0;

// ── REVENUE BY REGION ──────────────────────────────────────
const byRegion = {};
factSales.forEach(r => {
  const key = r.Region || 'Unknown';
  byRegion[key] = (byRegion[key] || 0) + (parseFloat(r.Revenue) || 0);
});
const byRegionSorted = Object.entries(byRegion).sort((a, b) => b[1] - a[1]);
const topRegion    = byRegionSorted[0]?.[0] || 'N/A';
const topRegionRev = byRegionSorted[0]?.[1] || 0;

// ── REVENUE BY MONTH ───────────────────────────────────────
const byMonth = {};
factSales.forEach(r => {
  const dateStr = r.Date || '';
  let label = 'Unknown';
  try {
    const d = new Date(dateStr);
    label = d.toLocaleString('default', { month: 'long', year: 'numeric' });
  } catch(e) {}
  byMonth[label] = (byMonth[label] || 0) + (parseFloat(r.Revenue) || 0);
});

// ── REVENUE BY QUARTER ─────────────────────────────────────
const byQuarter = {};
factSales.forEach(r => {
  const dateStr = r.Date || '';
  let label = 'Unknown';
  try {
    const d = new Date(dateStr);
    const q = Math.floor(d.getMonth() / 3) + 1;
    label = `Q${q} ${d.getFullYear()}`;
  } catch(e) {}
  byQuarter[label] = (byQuarter[label] || 0) + (parseFloat(r.Revenue) || 0);
});

// ── BEST & WORST MONTH ─────────────────────────────────────
const monthEntries = Object.entries(byMonth);
const bestMonth  = monthEntries.length ? monthEntries.reduce((a, b) => a[1] > b[1] ? a : b)[0] : 'N/A';
const worstMonth = monthEntries.length ? monthEntries.reduce((a, b) => a[1] < b[1] ? a : b)[0] : 'N/A';

// ── MOM GROWTH (last 2 months) ─────────────────────────────
const monthList = monthEntries;
let momGrowth = 0;
if (monthList.length >= 2) {
  const prevRev = monthList[monthList.length - 2][1];
  const currRev = monthList[monthList.length - 1][1];
  momGrowth = prevRev ? (((currRev - prevRev) / prevRev) * 100).toFixed(2) : 0;
}

// ── TOP 3 PRODUCTS TABLE ───────────────────────────────────
const topProductsTable = byProductSorted.slice(0, 3).map(([product, revenue]) => ({
  product,
  revenue: revenue.toFixed(2)
}));

// ── REGION TABLE ───────────────────────────────────────────
const regionTable = byRegionSorted.map(([region, revenue]) => ({
  region,
  revenue: revenue.toFixed(2)
}));

// ── RETURN ─────────────────────────────────────────────────
return [{
  json: {
    total_revenue:      parseFloat(totalRevenue.toFixed(2)),
    total_profit:       parseFloat(totalProfit.toFixed(2)),
    total_orders:       totalOrders,
    total_quantity:     totalQty,
    profit_margin:      parseFloat(profitMargin),
    avg_order_value:    parseFloat(avgOrderVal),
    top_product:        topProduct,
    top_product_rev:    parseFloat(topProductRev.toFixed(2)),
    top_customer:       topCustomer,
    top_customer_rev:   parseFloat(topCustomerRev.toFixed(2)),
    top_region:         topRegion,
    top_region_rev:     parseFloat(topRegionRev.toFixed(2)),
    best_month:         bestMonth,
    worst_month:        worstMonth,
    mom_growth:         parseFloat(momGrowth),
    monthly_trend:      JSON.stringify(byMonth),
    top_products_table: JSON.stringify(topProductsTable),
    region_table:       JSON.stringify(regionTable),
    by_quarter:         JSON.stringify(byQuarter),
    report_generated:   new Date().toISOString()
  }
}];

