// Extracts clean HTML from Groq/OpenAI response
const items = $input.all();
const raw = items[0].json;

// n8n surfaces Groq response in different places depending on node type
let htmlReport =
  raw?.message?.content ||
  raw?.text ||
  raw?.content ||
  JSON.stringify(raw);

// Strip markdown code fences if model wrapped output in ```html ... ```
if (typeof htmlReport === 'string' && htmlReport.includes('```')) {
  htmlReport = htmlReport
    .split('\n')
    .filter(line => !line.trim().startsWith('```'))
    .join('\n')
    .trim();
}

return [{ json: { html_report: htmlReport } }];
